{
  "children": [
    {
      "name": "ValidateBuildRequest",
      "purpose": "Validate the incoming build_request for required fields and business rules",
      "behavior": "Check action is one of trigger/status/list/cancel; for trigger ensure repo and config present; for status/cancel ensure build_id present; enforce one build per repo+branch constraint for trigger",
      "boundary": {
        "in_scope": [
          "validation of input fields",
          "checking business constraints"
        ],
        "out_of_scope": [
          "executing any build action",
          "modifying state"
        ]
      },
      "preconditions": [
        "build_request is a dict"
      ],
      "postconditions": [
        "if valid, validated_request has all required fields"
      ],
      "guarantees": [
        "no side effects on data stores"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "build_request",
          "type": "dict",
          "description": "the incoming request JSON",
          "source": "parent input"
        },
        {
          "name": "builds",
          "type": "Database",
          "description": "current build records to check constraints",
          "source": "internal leaf access"
        }
      ],
      "outputs": [
        {
          "name": "validated_request",
          "type": "dict",
          "description": "validated request with defaults applied",
          "consumer": "parent"
        },
        {
          "name": "validation_error",
          "type": "str",
          "description": "error message if validation fails",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateBuildRequest(build_request: dict, builds: Database) -> dict"
    },
    {
      "name": "TriggerBuild",
      "purpose": "Create a new build record, run compile and test steps, package artifacts, update status",
      "behavior": "Insert new build record with status 'running', execute compile step, then test step, on success package artifacts and set status 'completed', on failure set status 'failed'",
      "boundary": {
        "in_scope": [
          "creating build record",
          "running build steps",
          "storing artifacts",
          "updating status"
        ],
        "out_of_scope": [
          "validating request",
          "listing builds",
          "cancelling builds"
        ]
      },
      "preconditions": [
        "validated_request.action == 'trigger'",
        "no other running build for same repo+branch"
      ],
      "postconditions": [
        "build record created with final status",
        "artifacts stored if build succeeded"
      ],
      "guarantees": [
        "logs stored incrementally",
        "only one build per repo+branch runs at a time"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "validated_request",
          "type": "dict",
          "description": "validated trigger request with repo, branch, config",
          "source": "parent input"
        },
        {
          "name": "builds",
          "type": "Database",
          "description": "build records store",
          "source": "internal leaf access"
        },
        {
          "name": "artifacts",
          "type": "Database",
          "description": "artifacts store",
          "source": "internal leaf access"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "result with build_id, status, logs",
          "consumer": "parent"
        }
      ],
      "signature": "def TriggerBuild(validated_request: dict, builds: Database, artifacts: Database) -> dict"
    },
    {
      "name": "CheckBuildStatus",
      "purpose": "Return current status and logs for a given build_id",
      "behavior": "Look up build record by build_id, return its status and logs",
      "boundary": {
        "in_scope": [
          "querying build record",
          "returning status and logs"
        ],
        "out_of_scope": [
          "modifying state",
          "triggering builds",
          "listing builds"
        ]
      },
      "preconditions": [
        "validated_request.action == 'status'",
        "build_id exists in builds"
      ],
      "postconditions": [
        "no state change"
      ],
      "guarantees": [
        "returns current data"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "validated_request",
          "type": "dict",
          "description": "validated request with build_id",
          "source": "parent input"
        },
        {
          "name": "builds",
          "type": "Database",
          "description": "build records store",
          "source": "internal leaf access"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "result with build_id, status, logs",
          "consumer": "parent"
        }
      ],
      "signature": "def CheckBuildStatus(validated_request: dict, builds: Database) -> dict"
    },
    {
      "name": "ListBuildHistory",
      "purpose": "Return all build records filtered by optional repo/branch/status",
      "behavior": "Query builds store, apply filters from validated_request (repo, branch, status), return list of matching builds",
      "boundary": {
        "in_scope": [
          "filtering builds",
          "returning list"
        ],
        "out_of_scope": [
          "modifying state",
          "triggering builds",
          "cancelling builds"
        ]
      },
      "preconditions": [
        "validated_request.action == 'list'"
      ],
      "postconditions": [
        "no state change"
      ],
      "guarantees": [
        "returns all matching builds"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "validated_request",
          "type": "dict",
          "description": "validated request with optional filters",
          "source": "parent input"
        },
        {
          "name": "builds",
          "type": "Database",
          "description": "build records store",
          "source": "internal leaf access"
        }
      ],
      "outputs": [
        {
          "name": "build_list",
          "type": "list",
          "description": "list of build records",
          "consumer": "parent"
        }
      ],
      "signature": "def ListBuildHistory(validated_request: dict, builds: Database) -> list"
    },
    {
      "name": "CancelBuild",
      "purpose": "Stop a running build and update its status to 'cancelled'",
      "behavior": "Look up build by build_id, if status is 'running' set status to 'cancelled' and stop execution; if already completed, no-op",
      "boundary": {
        "in_scope": [
          "stopping running build",
          "updating status"
        ],
        "out_of_scope": [
          "triggering builds",
          "listing builds",
          "checking status"
        ]
      },
      "preconditions": [
        "validated_request.action == 'cancel'",
        "build_id exists in builds"
      ],
      "postconditions": [
        "if build was running, status changed to 'cancelled'"
      ],
      "guarantees": [
        "no-op for completed builds"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "validated_request",
          "type": "dict",
          "description": "validated request with build_id",
          "source": "parent input"
        },
        {
          "name": "builds",
          "type": "Database",
          "description": "build records store",
          "source": "internal leaf access"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "result with build_id, status, logs",
          "consumer": "parent"
        }
      ],
      "signature": "def CancelBuild(validated_request: dict, builds: Database) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "build_request": "ValidateBuildRequest.build_request"
    },
    "parent_outputs_produced_by": {
      "build_result": "TriggerBuild.build_result, CheckBuildStatus.build_result, CancelBuild.build_result",
      "build_list": "ListBuildHistory.build_list"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "build_request",
      "to_node": "ValidateBuildRequest",
      "to_input": "build_request",
      "note": "pass raw request for validation"
    },
    {
      "from_node": "ValidateBuildRequest",
      "from_output": "validated_request",
      "to_node": "parent",
      "to_input": "validated_request",
      "note": "return validated request to parent for routing"
    },
    {
      "from_node": "ValidateBuildRequest",
      "from_output": "validation_error",
      "to_node": "parent",
      "to_input": "validation_error",
      "note": "return error if validation fails"
    },
    {
      "from_node": "parent",
      "from_output": "validated_request",
      "to_node": "TriggerBuild",
      "to_input": "validated_request",
      "note": "route to trigger when action is trigger"
    },
    {
      "from_node": "parent",
      "from_output": "validated_request",
      "to_node": "CheckBuildStatus",
      "to_input": "validated_request",
      "note": "route to status when action is status"
    },
    {
      "from_node": "parent",
      "from_output": "validated_request",
      "to_node": "ListBuildHistory",
      "to_input": "validated_request",
      "note": "route to list when action is list"
    },
    {
      "from_node": "parent",
      "from_output": "validated_request",
      "to_node": "CancelBuild",
      "to_input": "validated_request",
      "note": "route to cancel when action is cancel"
    },
    {
      "from_node": "TriggerBuild",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return build result to parent"
    },
    {
      "from_node": "CheckBuildStatus",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return build result to parent"
    },
    {
      "from_node": "ListBuildHistory",
      "from_output": "build_list",
      "to_node": "parent",
      "to_input": "build_list",
      "note": "return build list to parent"
    },
    {
      "from_node": "CancelBuild",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return build result to parent"
    }
  ]
}
